import{_ as a,o as l,c as p,ag as n}from"./chunks/framework.f_9xDHrT.js";const g=JSON.parse('{"title":"钓法表达式（Angle Expression）","description":"","frontmatter":{},"headers":[],"relativePath":"guide/learn-angex.md","filePath":"guide/learn-angex.md","lastUpdated":null}'),e={name:"guide/learn-angex.md"};function d(c,s,o,t,i,r){return l(),p("div",null,[...s[0]||(s[0]=[n(`<h1 id="钓法表达式-angle-expression" tabindex="-1">钓法表达式（Angle Expression） <a class="header-anchor" href="#钓法表达式-angle-expression" aria-label="Permalink to &quot;钓法表达式（Angle Expression）&quot;">​</a></h1><blockquote><p>本文默认读者已经掌握《最终幻想14》中的基本操作和钓鱼玩法的各种基本要点。</p></blockquote><h1 id="本文还未完工" tabindex="-1">本文还未完工 <a class="header-anchor" href="#本文还未完工" aria-label="Permalink to &quot;本文还未完工&quot;">​</a></h1><h2 id="什么是钓法表达式" tabindex="-1">什么是钓法表达式？ <a class="header-anchor" href="#什么是钓法表达式" aria-label="Permalink to &quot;什么是钓法表达式？&quot;">​</a></h2><p>钓法表达式是一段用来描述 FF14 钓鱼玩法策略的文本，它由极简的关键字和符号组成，能快速表达特定场景或目标下的钓鱼方法。</p><blockquote><p>对于 MissFisher 来说，钓法表达式是用来快速为 MissFisher 输入钓鱼策略参数的。</p></blockquote><h2 id="_0-开始" tabindex="-1">0. 开始 <a class="header-anchor" href="#_0-开始" aria-label="Permalink to &quot;0. 开始&quot;">​</a></h2><h2 id="_0-1-怎么用" tabindex="-1">0.1 怎么用？ <a class="header-anchor" href="#_0-1-怎么用" aria-label="Permalink to &quot;0.1 怎么用？&quot;">​</a></h2><p>在已经启用 MissFisher 时，在游戏的聊天窗口（消息窗口）输入这样的命令：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mf &lt;angex&gt;</span></span></code></pre></div><p>例如钓法表达式是 <code>平钓》！！！</code>，那么：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mf 平钓》！！！</span></span></code></pre></div><p>又或者，你可以在 MissFisher 的<a href="#_02-钓法表达式编辑器">钓法表达式编辑器</a>中启动。</p><h2 id="_0-2-钓法表达式编辑器" tabindex="-1">0.2 钓法表达式编辑器 <a class="header-anchor" href="#_0-2-钓法表达式编辑器" aria-label="Permalink to &quot;0.2 钓法表达式编辑器&quot;">​</a></h2><p>在 MissFisher 主界面选择「预设」页签，点击「切换」，就能从钓法表达式生成器切换到钓法表达式编辑器。</p><p>钓法表达式编辑器可以：</p><ul><li>即时校验钓法表达式是否合法</li><li>将单行的钓法表达式按结构添加换行和缩进使其在编辑时更有可读性</li></ul><h2 id="_1-基本结构" tabindex="-1">1. 基本结构 <a class="header-anchor" href="#_1-基本结构" aria-label="Permalink to &quot;1. 基本结构&quot;">​</a></h2><blockquote><p>模式关键字 》 阶段参数</p></blockquote><p>一条最简的钓法表达式由「模式关键字」「阶段起始符」和「阶段参数」组成。</p><ul><li>例如：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 抛竿、对 <code>!</code> 提钩。</p><h2 id="_2-模式" tabindex="-1">2. 模式 <a class="header-anchor" href="#_2-模式" aria-label="Permalink to &quot;2. 模式&quot;">​</a></h2><h2 id="_2-1-平钓" tabindex="-1">2.1 平钓 <a class="header-anchor" href="#_2-1-平钓" aria-label="Permalink to &quot;2.1 平钓&quot;">​</a></h2><blockquote><p>普通的抛竿</p></blockquote><p><code>平钓</code> / <code>nm</code> 表示在这段钓法中不需要任何提升鱼类大尺寸概率的技能。即只需要抛竿，目标鱼类就有可能咬饵。</p><p>例如，钓场「红茶川水系下游」的钓场之王<a href="https://fish.ffmomola.com/#/wiki/fishing/spot/91/fish/7696" target="_blank" rel="noreferrer">「酿血鱼」</a>（ID 7696），它的钓法在各种攻略/工具中常被这样表示：</p><blockquote><p>「蝲蛄丸子」→ <code>!!!</code>「酿血鱼」</p></blockquote><p>简而言之：使用「蝲蛄丸子」，抛竿后对 <code>!!!</code> 提钩。</p><ul><li>先写 <code>平钓</code> / <code>nm</code><ul><li>表示在钓法中不使用提高大尺寸概率的技能，例如大鱼猎手或耐心系技能。</li></ul></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span>  </span>
<span class="line"><span class="dsl-mode">nm</span>  </span></code></pre></div><ul><li>然后使用 <code>》</code> / <code>&gt;</code> 引入阶段参数 <ul><li>每个「阶段」都必须使用 <code>》</code> / <code>&gt;</code> 来引入参数</li><li>通常来说，每次「从头开始」的抛竿和以小钓大，都算作一个单独的阶段</li><li>参数之间的空格不是必须的</li></ul></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span>  </span></code></pre></div><ul><li>最后，加上表示需要提钩的咬饵的类型符号 <ul><li>在这里，我们使用 3 个 <code>！</code> / <code>!</code> 来表示对应「酿血鱼」的咬饵类型：<code>！！！</code> / <code>!!!</code></li></ul></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 直接抛竿、对 <code>!!!</code> 提钩。</p><blockquote><p><strong>- 助记：</strong><br><code>平钓</code> / <code>nm</code> = 普通的抛竿</p></blockquote><h2 id="_2-2-大鱼" tabindex="-1">2.2 大鱼 <a class="header-anchor" href="#_2-2-大鱼" aria-label="Permalink to &quot;2.2 大鱼&quot;">​</a></h2><blockquote><p>大鱼猎手</p></blockquote><p><code>大鱼</code> / <code>bf</code> 表示在钓法中需要使用大鱼猎手，来提高获得大尺寸鱼类的概率。</p><p><strong>- 通常而言，我们在以下场景使用 <code>大鱼</code> / <code>bf</code>：</strong><br> 目标鱼类 / 用来以小钓大的鱼类 需要大尺寸，咬饵频次低且特征好分辨。</p><p>例如，钓场「彻悟岩窟」的钓场之王<a href="https://fish.ffmomola.com/#/wiki/fishing/spot/121/fish/15631" target="_blank" rel="noreferrer">「巨陨龟」</a>（ID 15631），它的钓法在各种攻略/工具中常被这样表示：</p><blockquote><p>「金属亮片」→ <code>!</code>「花岗蟹」→ <code>!!!</code>「巨陨龟」</p></blockquote><p>简而言之：使用「金属亮片」，抛竿后对 <code>!</code> 提钩，然后用「花岗蟹」以小钓大，对 <code>!!!</code> 提钩。<br> 也就是说，「巨陨龟」只需要 1 次以小钓大。</p><p>同时，在「彻悟岩窟」使用「金属亮片」时，咬饵的 <code>!</code> 必定是「花岗蟹」，咬饵的 <code>!!</code> 必定是「熔岩鲎」。<br> 这意味着，用来以小钓大的鱼类的咬饵特征非常好分辨。</p><p>只需要 1 次以小钓大，用来以小钓大的鱼类的咬饵特征又非常好分辨，这正好符合之前提到的 <code>大鱼</code> / <code>bf</code> 的使用场景。</p><ul><li>先写钓「花岗蟹」的表达式，使用 <code>大鱼</code> / <code>bf</code>、然后是 <code>》</code> / <code>&gt;</code>，补上咬饵类型 <code>!</code></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">大鱼</span><span class="dsl-op">》</span><span class="dsl-bite">！</span>  </span>
<span class="line"><span class="dsl-mode">bf</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span>  </span></code></pre></div><ul><li>再接上第 2 个 <code>》</code> / <code>&gt;</code>，表示在抛竿-提钩阶段结束后，尽可能使用以小钓大</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">大鱼</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">》</span>  </span>
<span class="line"><span class="dsl-mode">bf</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">&gt;</span>  </span></code></pre></div><ul><li>最后写上以小钓大后，需要提钩的目标鱼类的咬饵类型，即对应「巨陨龟」的 3 个 <code>！</code> / <code>!</code></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">大鱼</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>   </span>
<span class="line">   </span>
<span class="line"><span class="dsl-mode">bf</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 用大鱼猎手；<br> 在抛竿后对 <code>!</code> 提钩；尽可能以小钓大；在以小钓大后对 <code>!!!</code> 提钩。</p><blockquote><p><strong>- 助记：</strong><br><code>大鱼</code> / <code>bf</code> = 用「大鱼猎手」的钓法</p></blockquote><h2 id="_2-3-耐心" tabindex="-1">2.3 耐心 <a class="header-anchor" href="#_2-3-耐心" aria-label="Permalink to &quot;2.3 耐心&quot;">​</a></h2><blockquote><p>耐心系技能：耐心I、耐心II</p></blockquote><p><code>耐心</code> / <code>pt</code> 表示在钓法中需要使用「耐心系技能」（如耐心II），以在高频提钩场景下高效地提高获得大尺寸鱼类的概率。</p><p><strong>- 通常而言，我们在以下场景使用 <code>耐心</code> / <code>pt</code>：</strong><br> 目标鱼类 / 用来以小钓大的鱼类 需要大尺寸，咬饵频次高或特征难以分辨；<br> 或是目标鱼类需要使用 2 次或以上次数的以小钓大才能钓到。</p><p>例如，钓场「调查队冰洞」的钓场之王「一家之母」（ID 7946），它的钓法在各种攻略/工具中常被这样表示：</p><blockquote><p>「残暴水蛭」→ <code>!</code>「阿巴拉提亚公鱼」→ <code>!!!</code>「一家之母」</p></blockquote><p>简而言之：使用「残暴水蛭」，抛竿后对 <code>!</code> 提钩，然后使用「阿巴拉提亚公鱼」以小钓大，对 <code>!!!</code> 提钩。</p><p>在「调查队冰洞」中使用「残暴水蛭」垂钓时，咬饵的必定是「阿巴拉提亚公鱼」，如果仍使用技能大鱼猎手来提升大尺寸概率，采集力会在频繁的咬饵下迅速亏空。</p><p>因此，对于这种场景，我们会在钓法中使用耐心II而不是大鱼猎手：</p><ul><li>先写钓「阿巴拉提亚公鱼」的表达式，使用 <code>耐心</code> / <code>pt</code></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">耐心</span><span class="dsl-op">》</span><span class="dsl-bite">！</span>  </span>
<span class="line"><span class="dsl-mode">pt</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span>  </span></code></pre></div><ul><li>然后补全以小钓大后的阶段参数</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">耐心</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">pt</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 保持耐心系技能的状态效果；<br> 在抛竿后对 <code>!</code> 提钩；尽可能以小钓大；在以小钓大后对 <code>!!!</code> 提钩。</p><blockquote><p><strong>- 助记：</strong><br><code>耐心</code> / <code>pt</code> = 用「耐心II」的钓法</p></blockquote><h2 id="_3-咬饵类型" tabindex="-1">3. 咬饵类型 <a class="header-anchor" href="#_3-咬饵类型" aria-label="Permalink to &quot;3. 咬饵类型&quot;">​</a></h2><blockquote><p>竿型 杆型</p></blockquote><h2 id="_3-1-多个咬饵类型" tabindex="-1">3.1 多个咬饵类型 <a class="header-anchor" href="#_3-1-多个咬饵类型" aria-label="Permalink to &quot;3.1 多个咬饵类型&quot;">​</a></h2><p><code>+</code> 连接多个咬饵类型来组成咬饵类型集合。</p><p>例如：</p><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">+</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span><span class="dsl-op"> + </span><span class="dsl-bite">!!!</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 抛竿，对 <code>!</code> 或 <code>!!!</code> 提钩。</p><blockquote><ul><li><strong>约定：</strong><br> 在连接多个咬饵类型时，应按符号数量从小到大排列<br> 如：使用 <code>! + !!!</code> 而不是 <code>!!! + !</code></li></ul></blockquote><h2 id="_3-2-全部" tabindex="-1">3.2 全部 <a class="header-anchor" href="#_3-2-全部" aria-label="Permalink to &quot;3.2 全部&quot;">​</a></h2><p><code>全部</code> / <code>all</code> 表示「所有」咬饵类型。</p><p><code>全部</code> / <code>all</code><br> 等效于：<br><code>！+！！+！！！</code> / <code>! + !! + !!!</code></p><p>例如：</p><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 抛竿，对 <code>!</code> 或 <code>!!</code> 或 <code>!!!</code> 提钩。</p><h2 id="_3-3-额外咬饵类型" tabindex="-1">3.3 额外咬饵类型 <a class="header-anchor" href="#_3-3-额外咬饵类型" aria-label="Permalink to &quot;3.3 额外咬饵类型&quot;">​</a></h2><p>在 <code>》</code> / <code>&gt;</code> 后、被 <code>（ ）</code> / <code>( )</code> 包裹的是额外咬饵类型。表示需要对符合额外咬饵类型的咬饵使用「提钩」。</p><ul><li>例如：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-op">（</span><span class="dsl-bite">！！！</span><span class="dsl-op">）</span><span class="dsl-op">~</span><span class="dsl-time">11</span><span class="dsl-op">+</span><span class="dsl-time">20</span><span class="dsl-bite">！！</span><span class="dsl-hook">双提</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-op">(</span><span class="dsl-bite">!!!</span><span class="dsl-op">)</span> <span class="dsl-op">~</span> <span class="dsl-time">11</span> <span class="dsl-op">+</span> <span class="dsl-time">20</span> <span class="dsl-bite">!!</span> <span class="dsl-hook">dh</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 抛竿，对 20 秒以下（撒饵时 11 秒以下）的 <code>!!</code> 尽可能使用「双重提钩」；<br> 超时不歇竿，对 <code>!!!</code> 使用「提钩」。</p><blockquote><p>MissFisher 不会在当前阶段存在额外咬饵类型时、因为等待时间超过指定的最大咬饵时间而使用歇竿。</p></blockquote><h2 id="_3-4-以小钓大循环" tabindex="-1">3.4 以小钓大循环 <a class="header-anchor" href="#_3-4-以小钓大循环" aria-label="Permalink to &quot;3.4 以小钓大循环&quot;">​</a></h2><blockquote><p>套娃</p></blockquote><p>游戏中有这样的场景，当钓上鱼类 A，用它以小钓大并提钩后，钓上来的仍可能是鱼类 A，这被称为「以小钓大循环」。</p><p>例如钓场「深壕」的钓场之皇「潜龙」，必须用「以太螯虾」以小钓大才能钓到它。而用「以太螯虾」以小钓大，也可能钓到「以太螯虾」，这在各种攻略、钓鱼工具上可能会这样表示：</p><blockquote><p>「蜉蝣」→ <code>!!</code>「以太螯虾」（循环）→ <code>!!!</code>「潜龙」</p></blockquote><ul><li>只需要把相同的咬饵类型加入以小钓大后的咬饵类型集合中，就能表达这种以小钓大循环：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">耐心</span><span class="dsl-op">》</span><span class="dsl-bite">！！</span><span class="dsl-op">》</span><span class="dsl-bite">！！</span><span class="dsl-op">+</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">pt</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!</span><span class="dsl-op"> + </span><span class="dsl-bite">!!!</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 保持耐心系技能的状态效果；<br> 抛竿，对 <code>!!</code> 使用提钩；<br> 尽可能使用以小钓大，然后对 <code>!!</code> 或 <code>!!!</code> 使用提钩。</p><h2 id="_4-咬饵时间" tabindex="-1">4. 咬饵时间 <a class="header-anchor" href="#_4-咬饵时间" aria-label="Permalink to &quot;4. 咬饵时间&quot;">​</a></h2><h2 id="_4-1-不撒饵时的咬饵时间" tabindex="-1">4.1 不撒饵时的咬饵时间 <a class="header-anchor" href="#_4-1-不撒饵时的咬饵时间" aria-label="Permalink to &quot;4.1 不撒饵时的咬饵时间&quot;">​</a></h2><p>咬饵类型前被 <code>~</code> / <code>-</code> 连接的数字表示的是目标在未撒饵时的最短与最长咬饵时间。</p><ul><li><p>接受的咬饵时间的单位是秒</p></li><li><p>最多支持 1 位小数</p></li><li><p>例如：</p></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-time">10</span><span class="dsl-op">~</span><span class="dsl-time">32</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-time">10</span> <span class="dsl-op">~</span> <span class="dsl-time">32</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 直接抛竿、对咬饵时间在 10 秒以上、32 秒以下的 <code>!!!</code> 提钩。</p><blockquote><p>MissFisher 会在等待时间超过指定的咬饵时间时使用歇竿来取消等待。</p></blockquote><ul><li>可省略最短 / 最长咬饵时间以表示忽略最长 / 最短咬饵时间的限制 <ul><li>省略可以让表达式更简洁</li></ul></li><li>例如：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-time">10</span><span class="dsl-op">~</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-time">10</span> <span class="dsl-op">~</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 直接抛竿、对咬饵时间在 10 秒以上的 <code>!!!</code> 提钩。</p><h2 id="_4-2-撒饵时的咬饵时间" tabindex="-1">4.2 撒饵时的咬饵时间 <a class="header-anchor" href="#_4-2-撒饵时的咬饵时间" aria-label="Permalink to &quot;4.2 撒饵时的咬饵时间&quot;">​</a></h2><p><code>+</code> 连接的数字表示一组目标在不同状态时的咬饵时间，<code>+</code> 前的数字表示有撒饵时的咬饵时间，而 <code>+</code> 后的则是未撒饵时的咬饵时间。</p><ul><li>例如：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-time">6</span><span class="dsl-op">+</span><span class="dsl-time">10</span><span class="dsl-op">~</span><span class="dsl-time">17</span><span class="dsl-op">+</span><span class="dsl-time">32</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-time">6</span> <span class="dsl-op">+</span> <span class="dsl-time">10</span> <span class="dsl-op">~</span> <span class="dsl-time">17</span> <span class="dsl-op">+</span> <span class="dsl-time">32</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 直接抛竿；<br> 对咬饵时间在 10 秒以上（撒饵时 6 秒以上）、32 秒以下（撒饵时 17 秒以下）的 <code>!!!</code> 提钩。</p><blockquote><p>MissFisher 会在表达式中仅提供未撒饵时的咬饵时间时，按简单的公式补全出撒饵时的咬饵时间。<br> 例如：<br><code>10 ~ 32</code><br> 补全后：<br><code>5 + 10 ~ 17 + 32</code></p></blockquote><h2 id="_5-提钩类型" tabindex="-1">5. 提钩类型 <a class="header-anchor" href="#_5-提钩类型" aria-label="Permalink to &quot;5. 提钩类型&quot;">​</a></h2><p>咬饵类型后的关键字表示在对应的咬饵出现时应使用的提钩。</p><h2 id="_5-1-携带耐心状态时的提钩" tabindex="-1">5.1 携带耐心状态时的提钩 <a class="header-anchor" href="#_5-1-携带耐心状态时的提钩" aria-label="Permalink to &quot;5.1 携带耐心状态时的提钩&quot;">​</a></h2><p>咬饵类型后的 <code>强力</code> / <code>pw</code> 或 <code>精准</code> / <code>pc</code> 表示在符合前方参数的咬饵出现时，如果处在耐心系技能的负面状态效果，应使用的提钩技能。</p><ul><li>可以这样表达应对 <code>!!!</code> 类型的咬饵使用「精准提钩」</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">耐心</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span><span class="dsl-hook">精准</span>  </span>
<span class="line"><span class="dsl-mode">pt</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span> <span class="dsl-hook">pc</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> ……在以小钓大后对 <code>!!!</code> 提钩（如果处在耐心状态、则使用精准提钩）。</p><blockquote><ul><li><strong>约定：</strong><br><code>!!!</code> 后如果没有 <code>精准</code> / <code>pc</code> 则默认使用「强力提钩」</li></ul></blockquote><blockquote><p>MissFisher 会固定对 <code>!</code> 使用「精准提钩」、<br> 对 <code>!!</code> 使用「强力提钩」；<br> 对 <code>!!!</code> 默认使用「强力提钩」。</p></blockquote><h2 id="_5-2-复数的提钩" tabindex="-1">5.2 复数的提钩 <a class="header-anchor" href="#_5-2-复数的提钩" aria-label="Permalink to &quot;5.2 复数的提钩&quot;">​</a></h2><blockquote><p>多提</p></blockquote><p>咬饵类型后的 <code>双重</code> / <code>双提</code> / <code>dh</code> 或 <code>三重</code> / <code>三提</code> / <code>th</code> 表示在符合前方参数的咬饵出现时，应使用的可增加捕获到的鱼的数量的提钩技能。</p><ul><li>例如，表达使用「双重提钩」：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-hook">双重</span>  </span>
<span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-hook">双提</span>  </span>
<span class="line"><wbr></span>
<span class="line"><span class="dsl-mode">pt</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-hook">dh</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 抛竿，<code>!</code> 出现时，尽可能使用「双重提钩」。</p><h2 id="_5-3-其他特殊的提钩" tabindex="-1">5.3 其他特殊的提钩 <a class="header-anchor" href="#_5-3-其他特殊的提钩" aria-label="Permalink to &quot;5.3 其他特殊的提钩&quot;">​</a></h2><p>咬饵类型后的 <code>华丽</code> / <code>sh</code> 表示在符合前方参数的咬饵出现时，应使用「华丽提钩」。</p><ul><li>例如：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span><span class="dsl-hook">华丽</span>  </span>
<span class="line"><span class="dsl-mode">pt</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span> <span class="dsl-hook">sh</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 抛竿，<code>!!!</code> 出现时，尽可能使用「华丽提钩」。</p><h2 id="_6-用来以小钓大的目标" tabindex="-1">6. 用来以小钓大的目标 <a class="header-anchor" href="#_6-用来以小钓大的目标" aria-label="Permalink to &quot;6. 用来以小钓大的目标&quot;">​</a></h2><p>在表示以小钓大参数起始的 <code>》</code> / <code>&gt;</code> 前的、被 <code>【 】</code> / <code>[ ]</code> 包裹的名称或数字 ID 表示用来以小钓大的目标鱼类。</p><p>例如钓场之王「一家之母」，需要使用「阿巴拉提亚公鱼」来以小钓大才能钓到它，钓法如：</p><blockquote><p>「残暴水蛭」→ <code>!</code>「阿巴拉提亚公鱼」→ <code>!!!</code>「一家之母」</p></blockquote><ul><li>显式表达应使用「阿巴拉提亚公鱼」来以小钓大： <ul><li>在表示以小钓大的第 2 个 <code>》</code> / <code>&gt;</code> 开始前添加</li></ul></li></ul><div class="language-diff vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="diff-remove">- <span class="dsl-mode">耐心</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span></span>
<span class="line"><span class="diff-add">+ <span class="dsl-mode">耐心</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="diff-token-change"><span class="dsl-op">【</span><span class="dsl-name">阿巴拉提亚公鱼</span><span class="dsl-op">】</span></span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span></span>
<span class="line"><span class="diff-remove">- <span class="dsl-mode">pt</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>   </span></span>
<span class="line"><span class="diff-add">+ <span class="dsl-mode">pt</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="diff-token-change"><span class="dsl-op">[</span><span class="dsl-name">Abalathian Smelt</span><span class="dsl-op">]</span></span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></span></code></pre></div><h2 id="_7-内联表达式" tabindex="-1">7. 内联表达式 <a class="header-anchor" href="#_7-内联表达式" aria-label="Permalink to &quot;7. 内联表达式&quot;">​</a></h2><h2 id="_7-1-拍击水面" tabindex="-1">7.1 拍击水面 <a class="header-anchor" href="#_7-1-拍击水面" aria-label="Permalink to &quot;7.1 拍击水面&quot;">​</a></h2><p>紧跟着 <code>@</code> 的 <code>拍水</code> / <code>ss</code> 开始的是拍击水面类型的内联表达式。</p><p>假设拍水目标是 <code>魇鱼</code> / <code>Feverfish</code>：</p><ul><li>在平钓后的阶段参数最后写 <code>@</code></li></ul><div class="language-diff vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="diff-remove">- <span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span>  </span></span>
<span class="line"><span class="diff-add">+ <span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="diff-token-change"><span class="dsl-op">@</span></span>  </span></span>
<span class="line"><span class="diff-remove">- <span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span>  </span></span>
<span class="line"><span class="diff-add">+ <span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="diff-token-change"><span class="dsl-op">@</span></span>  </span></span></code></pre></div><ul><li>加上 <code>拍水</code> / <code>ss</code></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span>  </span></code></pre></div><ul><li>最后追加要对其使用拍击水面的目标</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-op">【</span><span class="dsl-name">魇鱼</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-op">[</span><span class="dsl-name">Feverfish</span><span class="dsl-op">]</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 直接抛竿、然后对任何咬饵提钩；<br> 如果钓到了 <code>魇鱼</code> / <code>Feverfish</code>，则对其使用拍击水面。</p><ul><li>如果钓法包含拍击水面类型的内联表达式，同时还需要以小钓大，看起来会是这样：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">耐心</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-op">【</span><span class="dsl-name">魇鱼</span><span class="dsl-op">】</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span>  </span>
<span class="line"><span class="dsl-mode">pt</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-op">[</span><span class="dsl-name">Feverfish</span><span class="dsl-op">]</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span>  </span></code></pre></div><blockquote><p><strong>- 助记：</strong><br> 内联表达式：<code>@</code> 内联类型 参数</p></blockquote><h2 id="目标参数的其他写法" tabindex="-1">目标参数的其他写法 <a class="header-anchor" href="#目标参数的其他写法" aria-label="Permalink to &quot;目标参数的其他写法&quot;">​</a></h2><ul><li>可以直接使用物品的数字 ID</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-op">【</span><span class="dsl-id">36468</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-op">[</span><span class="dsl-id">36468</span><span class="dsl-op">]</span>  </span></code></pre></div><ul><li><code>|</code> 连接名称和数字 ID 时可提升可读性 <ul><li>并列时，名称在前，数字 ID 在后</li></ul></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-op">【</span><span class="dsl-name">魇鱼</span><span class="dsl-op">|</span><span class="dsl-id">36468</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-op">[</span><span class="dsl-name">Feverfish</span><span class="dsl-op">|</span><span class="dsl-id">36468</span><span class="dsl-op">]</span>  </span></code></pre></div><blockquote><p>当名称和数字 ID 并列，MissFisher 会优先使用数字 ID；<br> 在使用名称时，最好同时使用数字 ID 来避免名称书写或识别时的错误。</p></blockquote><ul><li><code>、</code> / <code>||</code> 会连接多个目标组成集合</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-op">【</span><span class="dsl-name">魇鱼</span><span class="dsl-op">|</span><span class="dsl-id">36468</span><span class="dsl-sep">、</span><span class="dsl-name">紫鱼</span><span class="dsl-op">|</span><span class="dsl-id">36470</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-op">[</span><span class="dsl-name">Feverfish</span><span class="dsl-op">|</span><span class="dsl-id">36468</span> <span class="dsl-sep">||</span> <span class="dsl-name">Calicia</span><span class="dsl-op">|</span><span class="dsl-id">36470</span><span class="dsl-op">]</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> ……如果钓到了 <code>36468</code> 或者 <code>36470</code>，则尽可能对其使用拍击水面。</p><ul><li><code>任何</code> / <code>any</code> 表示任何鱼类</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-op">【</span><span class="dsl-literal">任何</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-op">[</span><span class="dsl-literal">any</span><span class="dsl-op">]</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> ……对任何鱼类都尽可能对其使用拍击水面。</p><ul><li><code>【 】</code> / <code>[ ]</code> 的开头的 <code>？</code> / <code>?</code> 会对整个集合取反</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-op">【</span><span class="dsl-op">？</span><span class="dsl-id">36468</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-op">[</span><span class="dsl-op">?</span> <span class="dsl-id">36468</span><span class="dsl-op">]</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> ……如果钓到了不同于 <code>36468</code> 的鱼类，则尽可能对其使用拍击水面。</p><ul><li><code>占位</code> / <code>ph</code> 表示一个空集，等效于 <code>？任何</code> / <code>? any</code></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-op">【</span><span class="dsl-literal">占位</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-op">[</span><span class="dsl-literal">ph</span><span class="dsl-op">]</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> ……不对任何鱼类使用拍击水面。</p><ul><li>像这样，可以利用 <code>占位</code> / <code>ph</code> 和拍击水面目标参数来表达需要对额外的咬饵使用提钩（而不对任何鱼类使用拍击水面）</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-op">~</span><span class="dsl-time">9</span><span class="dsl-bite">！！</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-op">~</span><span class="dsl-time">5</span><span class="dsl-bite">！</span><span class="dsl-op">【</span><span class="dsl-literal">占位</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-op">~</span> <span class="dsl-time">9</span> <span class="dsl-bite">!!</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-op">~</span> <span class="dsl-time">5</span> <span class="dsl-bite">!</span> <span class="dsl-op">[</span><span class="dsl-literal">ph</span><span class="dsl-op">]</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 抛竿、对 9 秒以内的 <code>!!</code> 使用提钩，<br> 同时也对 5 秒以内 <code>!</code> 使用提钩。</p><h2 id="_7-1-2-拍击水面目标的咬饵参数" tabindex="-1">7.1.2 拍击水面目标的咬饵参数 <a class="header-anchor" href="#_7-1-2-拍击水面目标的咬饵参数" aria-label="Permalink to &quot;7.1.2 拍击水面目标的咬饵参数&quot;">​</a></h2><p>在 <code>拍水</code> / <code>ss</code> 后、拍击水面目标前的，是拍击水面目标的咬饵参数。</p><ul><li>例如「酿血鱼」</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><p>占据咬饵概率的 <code>4936</code> 的咬饵类型是 <code>!!</code>，不为拍击水面目标指定咬饵的话，就无法钓到 <code>4936</code> 来使用拍击水面了。</p><ul><li>像这样就可以为表达式指定拍击水面目标的咬饵参数：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-bite">！！</span><span class="dsl-op">【</span><span class="dsl-name">白妙鲤</span><span class="dsl-op">|</span><span class="dsl-id">4936</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-bite">!!</span> <span class="dsl-op">[</span><span class="dsl-name">Maiden Carp</span><span class="dsl-op">|</span><span class="dsl-id">4936</span><span class="dsl-op">]</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 抛竿、对 <code>!!!</code> 使用提钩；<br> 在需要拍击水面且采集力充足时，对 <code>!!</code> 使用提钩；<br> 如果钓到了 <code>4936</code>，则尽可能对其使用拍击水面。</p><ul><li>如果还要指定咬饵时间的话：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-time">12</span><span class="dsl-op">~</span><span class="dsl-bite">！！</span><span class="dsl-op">【</span><span class="dsl-name">白妙鲤</span><span class="dsl-op">|</span><span class="dsl-id">4936</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-time">12</span> <span class="dsl-op">~</span> <span class="dsl-bite">!!</span> <span class="dsl-op">[</span><span class="dsl-name">Maiden Carp</span><span class="dsl-op">|</span><span class="dsl-id">4936</span><span class="dsl-op">]</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> ……在需要拍击水面且采集力充足时，对 12 秒以上的 <code>!!</code> 使用提钩；<br> 如果钓到了 <code>4936</code>，则尽可能对其使用拍击水面。</p><h2 id="_7-2-专一垂钓" tabindex="-1">7.2 专一垂钓 <a class="header-anchor" href="#_7-2-专一垂钓" aria-label="Permalink to &quot;7.2 专一垂钓&quot;">​</a></h2><p>紧跟着 <code>@</code> 的 <code>专一</code> / <code>ic</code> 开始的是专一垂钓类型的内联表达式。</p><ul><li>例如，钓到「黄金鳗」时，对其使用专一垂钓：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！！</span><span class="dsl-op">@</span><span class="dsl-trigger">专一</span><span class="dsl-op">【</span><span class="dsl-name">黄金鳗</span><span class="dsl-op">|</span><span class="dsl-id">46188</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!</span> <span class="dsl-op">@</span><span class="dsl-trigger">ic</span> <span class="dsl-op">[</span><span class="dsl-name">Goldentail</span><span class="dsl-op">|</span><span class="dsl-id">46188</span><span class="dsl-op">]</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> ……如果钓到了 <code>46188</code>，则尽可能对其使用专一垂钓。</p><p>专一垂钓类型的内联表达式无法指定咬饵特征。</p><ul><li>但可以这样指定持有专一垂钓状态效果时，对咬饵使用的提钩类型： <ul><li>在专一提钩目标后写要使用的提钩</li></ul></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！！</span><span class="dsl-op">@</span><span class="dsl-trigger">专一</span><span class="dsl-op">【</span><span class="dsl-name">黄金鳗</span><span class="dsl-op">|</span><span class="dsl-id">46188</span><span class="dsl-op">】</span><span class="dsl-name">双提</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!</span> <span class="dsl-op">@</span><span class="dsl-trigger">ic</span> <span class="dsl-op">[</span><span class="dsl-name">Goldentail</span><span class="dsl-op">|</span><span class="dsl-id">46188</span><span class="dsl-op">]</span> <span class="dsl-name">dh</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> ……如果钓到了 <code>46188</code>，则尽可能对其使用专一垂钓；<br> 在持有专一垂钓状态效果时，对任何咬饵尽可能使用「双重提钩」。</p><ul><li>同时存在专一垂钓和拍击水面类型的内联表达式时，应先写拍击水面类型的内联表达式，然后写专一垂钓类型的内联表达式：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！！</span><span class="dsl-op">@</span><span class="dsl-trigger">拍水</span><span class="dsl-op">【</span><span class="dsl-name">亚斯拉尼弓鳍鱼</span><span class="dsl-op">|</span><span class="dsl-id">43773</span><span class="dsl-op">】</span><span class="dsl-op">@</span><span class="dsl-trigger">专一</span><span class="dsl-op">【</span><span class="dsl-name">黄金鳗</span><span class="dsl-op">|</span><span class="dsl-id">46188</span><span class="dsl-op">】</span><span class="dsl-name">双提</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!</span> <span class="dsl-op">@</span><span class="dsl-trigger">ss</span> <span class="dsl-op">[</span><span class="dsl-name">Yyasulani Bowfin</span><span class="dsl-op">|</span><span class="dsl-id">43773</span><span class="dsl-op">]</span> <span class="dsl-op">@</span><span class="dsl-trigger">ic</span> <span class="dsl-op">[</span><span class="dsl-name">Goldentail</span><span class="dsl-op">|</span><span class="dsl-id">46188</span><span class="dsl-op">]</span> <span class="dsl-name">dh</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> ……如果钓到了 <code>43773</code>，则尽可能对其使用拍击水面；<br> 如果钓到了 <code>46188</code>，则尽可能对其使用专一垂钓；<br> 在持有专一垂钓状态效果时，对任何咬饵尽可能使用「双重提钩」。</p><h2 id="_8-游动饵" tabindex="-1">8. 游动饵 <a class="header-anchor" href="#_8-游动饵" aria-label="Permalink to &quot;8. 游动饵&quot;">​</a></h2><blockquote><p>鱼篓</p></blockquote><p><code>《</code> / <code>&lt;</code> 后跟随被 <code>【 】</code> / <code>[ ]</code> 包裹的目标，表示需要将可以小钓大的目标鱼类保留为游动饵。同时表示应采用尽可能提高钓到鱼类的大尺寸概率的手法。</p><ul><li>例如：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">耐心</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">《</span><span class="dsl-op">【</span><span class="dsl-id">4869</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">pt</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">&lt;</span> <span class="dsl-op">[</span><span class="dsl-id">4869</span><span class="dsl-op">]</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 保持耐心系技能的状态效果；<br> 抛竿、对 <code>!</code> 使用提钩；<br> 尽可能对 <code>4869</code> 使用「熟练妙招」（来将其保留为游动饵）。</p><h2 id="_8-1-指定准备时存入的游动饵" tabindex="-1">8.1 指定准备时存入的游动饵 <a class="header-anchor" href="#_8-1-指定准备时存入的游动饵" aria-label="Permalink to &quot;8.1 指定准备时存入的游动饵&quot;">​</a></h2><p><code>《</code> / <code>&lt;</code> 指定了在准备游动饵时应保留为游动饵的鱼类。</p><p>例如，钓场「蛇水湖」的钓场之皇<a href="https://fish.ffmomola.com/#/wiki/fishing/spot/225/fish/33243" target="_blank" rel="noreferrer">「隆卡的大水蛇？」</a>，其钓法如下：</p><blockquote><p>「盗蟹丸」→ <code>!</code>「王冠脂鲤」→ <code>!!</code>「引螈」→ <code>!!!</code>「洛克瓦卫兵」→ <code>!!!</code>「隆卡的大水蛇？」</p></blockquote><p>「隆卡的大水蛇？」需要用「洛克瓦卫兵」以小钓大才能钓到。<br> 然而，「洛克瓦卫兵」的窗口期与前者一致，所以在「隆卡的大水蛇？」的窗口期前准备的游动饵应是用来钓「洛克瓦卫兵」的「引螈」。</p><ul><li>写成表达式的话： <ul><li>表达在准备游动饵时，钓到 <code>27491</code> 后就应该把它保留为游动饵（而不是继续以小钓大）</li></ul></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">耐心</span><span class="dsl-op">@</span><span class="dsl-time">1000</span><span class="dsl-op">-</span><span class="dsl-time">1200</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">》</span><span class="dsl-bite">！！</span><span class="dsl-op">《</span><span class="dsl-op">【</span><span class="dsl-id">27491</span><span class="dsl-op">】</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">pt</span> <span class="dsl-op">@</span><span class="dsl-time">1000</span> <span class="dsl-op">-</span> <span class="dsl-time">1200</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!</span> <span class="dsl-op">&lt;</span> <span class="dsl-op">[</span><span class="dsl-id">27491</span><span class="dsl-op">]</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><h2 id="_9-钓饵" tabindex="-1">9. 钓饵 <a class="header-anchor" href="#_9-钓饵" aria-label="Permalink to &quot;9. 钓饵&quot;">​</a></h2><blockquote><p>鱼饵、渔饵</p></blockquote><p>模式关键字后用 <code>【 】</code> / <code>[ ]</code> 包裹的最多 1 种明确的钓饵名，表示在这段钓法中应使用的钓饵。</p><ul><li>例如，钓「酿血鱼」需要使用「蝲蛄丸子」：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">【</span><span class="dsl-name">蝲蛄丸子</span><span class="dsl-op">】</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">[</span><span class="dsl-name">Crayfish Ball</span><span class="dsl-op">]</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> 使用钓饵「蝲蛄丸子」；……</p><p>也可以使用和目标参数同样的其他写法，详见<a href="#_目标参数的其他写法">目标参数的其他写法</a>。</p><h2 id="_10-窗口期" tabindex="-1">10. 窗口期 <a class="header-anchor" href="#_10-窗口期" aria-label="Permalink to &quot;10. 窗口期&quot;">​</a></h2><p>在 <code>》</code> / <code>&gt;</code> 前用 <code>@</code> 开始窗口期条件。</p><p><code>-</code> 连接的 4 位数表示对应鱼类会出现的 24 小时制的艾欧泽亚时间区间。</p><p><code>（ ）</code> / <code>( )</code> 包围的天气表示对应鱼类会出现的天气，内部的 <code>=》</code> / <code>=&gt;</code> 连接「之前的天气」和「现在的天气」。</p><ul><li>例如，对应鱼类在艾欧泽亚时间的 10:00 到 12:00 才会出现：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">@</span><span class="dsl-time">1000</span><span class="dsl-op">-</span><span class="dsl-time">1200</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">@</span><span class="dsl-time">1000</span> <span class="dsl-op">-</span> <span class="dsl-time">1200</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><ul><li>又例如，对应鱼类在当前天气是 <code>薄雾</code> / <code>Fog</code> 时才会出现：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">@</span><span class="dsl-op">（</span><span class="dsl-name">薄雾</span><span class="dsl-op">）</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">@</span><span class="dsl-op">(</span><span class="dsl-name">Fog</span><span class="dsl-op">)</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><ul><li>如果要求之前的天气是 <code>阴云</code> / <code>Clouds</code>，同时现在的天气是 <code>薄雾</code> / <code>Fog</code>：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">@</span><span class="dsl-op">（</span><span class="dsl-name">阴云</span><span class="dsl-op">=》</span><span class="dsl-name">薄雾</span><span class="dsl-op">）</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">@</span><span class="dsl-op">(</span><span class="dsl-name">Clouds</span><span class="dsl-op"> =&gt; </span><span class="dsl-name">Fog</span><span class="dsl-op">)</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><ul><li>如果同时要求时间和天气条件，先写时间，然后写天气：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">@</span><span class="dsl-time">1000</span><span class="dsl-op">-</span><span class="dsl-time">1200</span><span class="dsl-op">（</span><span class="dsl-name">阴云</span><span class="dsl-op">=》</span><span class="dsl-name">薄雾</span><span class="dsl-op">）</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">@</span><span class="dsl-time">1000</span> <span class="dsl-op">-</span> <span class="dsl-time">1200</span> <span class="dsl-op">(</span><span class="dsl-name">Clouds</span><span class="dsl-op"> =&gt; </span><span class="dsl-name">Fog</span><span class="dsl-op">)</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span>  </span></code></pre></div><blockquote><p>MissFisher 会在窗口期外按钓法所需自动预备「捕鱼人之计」、游动饵等。</p></blockquote><h2 id="_11-全局参数" tabindex="-1">11. 全局参数 <a class="header-anchor" href="#_11-全局参数" aria-label="Permalink to &quot;11. 全局参数&quot;">​</a></h2><p>在所有阶段参数的最后以 <code>=</code> 开始，并用 <code>；</code> 或 <code>;</code> 分割或结束的是全局参数。</p><h2 id="_11-1-最终目标" tabindex="-1">11.1 最终目标 <a class="header-anchor" href="#_11-1-最终目标" aria-label="Permalink to &quot;11.1 最终目标&quot;">​</a></h2><p>在 <code>=</code> 后的不带数字的用 <code>【 】</code> / <code>[ ]</code> 包裹的目标集合是最终目标，它会被 <code>；</code> / <code>;</code> 结束。</p><p>最终目标表示在钓上集合中的鱼类后就停止钓鱼。</p><ul><li>例如，最终目标是 <code>4869</code><ul><li>先写用来钓 <code>4869</code> 的表达式：</li></ul></li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span>  </span></code></pre></div><ul><li>用 <code>=</code> 开始全局参数</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">=</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">=</span>  </span></code></pre></div><ul><li>接着写带 <code>4869</code> 的目标集合</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">=</span><span class="dsl-op">【</span><span class="dsl-id">4869</span><span class="dsl-op">】</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">=</span> <span class="dsl-op">[</span><span class="dsl-id">4869</span><span class="dsl-op">]</span>  </span></code></pre></div><ul><li>最后用 <code>；</code> / <code>;</code> 结束</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">=</span><span class="dsl-op">【</span><span class="dsl-id">4869</span><span class="dsl-op">】</span><span class="dsl-sep">；</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">=</span> <span class="dsl-op">[</span><span class="dsl-id">4869</span><span class="dsl-op">]</span><span class="dsl-sep">;</span>  </span></code></pre></div><p><strong>表达钓法：</strong><br> ……钓到 <code>4869</code> 时停止钓鱼。</p><h2 id="_11-2-计数器" tabindex="-1">11.2 计数器 <a class="header-anchor" href="#_11-2-计数器" aria-label="Permalink to &quot;11.2 计数器&quot;">​</a></h2><p>在 <code>=</code> 后的、带数字的、用 <code>【 】</code> / <code>[ ]</code> 包裹的目标集合是计数器，它会被 <code>；</code> / <code>;</code> 结束 / 分割。</p><p>在钓到符合集合中目标的鱼类时，计数加 1。如果所有计数器已计算的数量都满足指定数量，则停止钓鱼。计数目标最多支持 3 组。</p><ul><li>例如，表达钓 3 条 <code>4869</code> 就停止钓鱼：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">=</span><span class="dsl-time">3</span><span class="dsl-op">【</span><span class="dsl-id">4869</span><span class="dsl-op">】</span><span class="dsl-sep">；</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">=</span> <span class="dsl-time">3</span> <span class="dsl-op">[</span><span class="dsl-id">4869</span><span class="dsl-op">]</span><span class="dsl-sep">;</span>  </span></code></pre></div><ul><li>又或者，表达钓 3 条 <code>4869</code> 和 2 条 <code>4904</code> 就停止钓鱼：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">=</span><span class="dsl-time">3</span><span class="dsl-op">【</span><span class="dsl-id">4869</span><span class="dsl-op">】</span><span class="dsl-sep">；</span><span class="dsl-time">2</span><span class="dsl-op">【</span><span class="dsl-id">4904</span><span class="dsl-op">】</span><span class="dsl-sep">；</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">=</span> <span class="dsl-time">3</span> <span class="dsl-op">[</span><span class="dsl-id">4869</span><span class="dsl-op">]</span><span class="dsl-sep">;</span> <span class="dsl-time">2</span> <span class="dsl-op">[</span><span class="dsl-id">4904</span><span class="dsl-op">]</span><span class="dsl-sep">;</span>  </span></code></pre></div><ul><li>又如，结合最终目标，钓到 <code>4913</code> 就停止钓鱼； 同时，如果钓够 3 条 <code>4869</code> 和 2 条 <code>4904</code> 也停止钓鱼：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">=</span><span class="dsl-op">【</span><span class="dsl-id">4913</span><span class="dsl-op">】</span><span class="dsl-sep">；</span><span class="dsl-time">3</span><span class="dsl-op">【</span><span class="dsl-id">4869</span><span class="dsl-op">】</span><span class="dsl-sep">；</span><span class="dsl-time">2</span><span class="dsl-op">【</span><span class="dsl-id">4904</span><span class="dsl-op">】</span><span class="dsl-sep">；</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">=</span> <span class="dsl-op">[</span><span class="dsl-id">4913</span><span class="dsl-op">]</span><span class="dsl-sep">;</span> <span class="dsl-time">3</span> <span class="dsl-op">[</span><span class="dsl-id">4869</span><span class="dsl-op">]</span><span class="dsl-sep">;</span> <span class="dsl-time">2</span> <span class="dsl-op">[</span><span class="dsl-id">4904</span><span class="dsl-op">]</span><span class="dsl-sep">;</span>  </span></code></pre></div><h2 id="_11-3-钓法修饰词" tabindex="-1">11.3 钓法修饰词 <a class="header-anchor" href="#_11-3-钓法修饰词" aria-label="Permalink to &quot;11.3 钓法修饰词&quot;">​</a></h2><p>在 <code>=</code> 后的关键字是钓法修饰词，它会被 <code>、</code> / <code>||</code> 分割，并被 <code>；</code> / <code>;</code> 结束。</p><ul><li>语法如：</li></ul><div class="language-diff vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="diff-remove">- <span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span>  </span></span>
<span class="line"><span class="diff-add">+ <span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="diff-token-change"><span class="dsl-op">=</span><span class="dsl-modifier">不撒饵</span><span class="dsl-sep">；</span></span>  </span></span>
<span class="line"><span class="diff-remove">- <span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span>  </span></span>
<span class="line"><span class="diff-add">+ <span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="diff-token-change"><span class="dsl-op">=</span> <span class="dsl-modifier">nochum</span><span class="dsl-sep">;</span></span>   </span></span></code></pre></div><ul><li>同时表达多个钓法修饰词：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">=</span><span class="dsl-modifier">不撒饵</span><span class="dsl-sep">、</span><span class="dsl-modifier">钓组</span><span class="dsl-sep">；</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">=</span> <span class="dsl-modifier">nochum</span> <span class="dsl-op">|</span><span class="dsl-op">|</span> <span class="dsl-modifier">snag</span><span class="dsl-sep">;</span>   </span></code></pre></div><ul><li>可与其他全局参数同时存在，如最终目标和计数目标：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">》</span><span class="dsl-bite">！</span><span class="dsl-op">=</span><span class="dsl-op">【</span><span class="dsl-id">4869</span><span class="dsl-op">】</span><span class="dsl-sep">；</span><span class="dsl-time">2</span><span class="dsl-op">【</span><span class="dsl-id">4904</span><span class="dsl-op">】</span><span class="dsl-sep">；</span><span class="dsl-modifier">不撒饵</span><span class="dsl-sep">、</span><span class="dsl-modifier">钓组</span><span class="dsl-sep">；</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!</span> <span class="dsl-op">=</span> <span class="dsl-op">[</span><span class="dsl-id">4869</span><span class="dsl-op">]</span><span class="dsl-sep">;</span> <span class="dsl-time">2</span> <span class="dsl-op">[</span><span class="dsl-id">4904</span><span class="dsl-op">]</span><span class="dsl-sep">;</span> <span class="dsl-modifier">nochum</span> <span class="dsl-op">|</span><span class="dsl-op">|</span> <span class="dsl-modifier">snag</span><span class="dsl-sep">;</span>   </span></code></pre></div><p>所有钓法修饰词：</p><table tabindex="0"><thead><tr><th style="text-align:center;">中文输入法</th><th style="text-align:center;">英文输入法</th></tr></thead><tbody><tr><td style="text-align:center;">鱼眼</td><td style="text-align:center;">fe</td></tr><tr><td style="text-align:center;">攒鱼计</td><td style="text-align:center;">aa</td></tr><tr><td style="text-align:center;">不撒饵</td><td style="text-align:center;">nochum</td></tr><tr><td style="text-align:center;">无强心剂</td><td style="text-align:center;">nocord</td></tr><tr><td style="text-align:center;">无恩宠</td><td style="text-align:center;">nofavor</td></tr><tr><td style="text-align:center;">允许溢出</td><td style="text-align:center;">overflow</td></tr><tr><td style="text-align:center;">梭哈</td><td style="text-align:center;">all-in</td></tr><tr><td style="text-align:center;">钓组</td><td style="text-align:center;">snag</td></tr><tr><td style="text-align:center;">收藏品</td><td style="text-align:center;">coll</td></tr><tr><td style="text-align:center;">不收集</td><td style="text-align:center;">nocoll</td></tr><tr><td style="text-align:center;">大尺寸</td><td style="text-align:center;">large</td></tr><tr><td style="text-align:center;">大鱼知识</td><td style="text-align:center;">bfg</td></tr><tr><td style="text-align:center;">鱼篓</td><td style="text-align:center;">sh</td></tr><tr><td style="text-align:center;">鱼篓专一</td><td style="text-align:center;">sh-ic</td></tr><tr><td style="text-align:center;">等待专一</td><td style="text-align:center;">waitic</td></tr><tr><td style="text-align:center;">等待华丽</td><td style="text-align:center;">wait-sh</td></tr><tr><td style="text-align:center;">套娃</td><td style="text-align:center;">mooch-loop</td></tr><tr><td style="text-align:center;">引诱</td><td style="text-align:center;">lure</td></tr><tr><td style="text-align:center;">雄心</td><td style="text-align:center;">a-lure</td></tr><tr><td style="text-align:center;">谦逊</td><td style="text-align:center;">m-lure</td></tr><tr><td style="text-align:center;">鱼影</td><td style="text-align:center;">shadow</td></tr><tr><td style="text-align:center;">重随</td><td style="text-align:center;">re-roll</td></tr><tr><td style="text-align:center;">回收</td><td style="text-align:center;">recy</td></tr><tr><td style="text-align:center;">加钩</td><td style="text-align:center;">mh</td></tr><tr><td style="text-align:center;">确保多提</td><td style="text-align:center;">mhs</td></tr><tr><td style="text-align:center;">多提回退</td><td style="text-align:center;">mhs-back</td></tr><tr><td style="text-align:center;">银星</td><td style="text-align:center;">silver</td></tr><tr><td style="text-align:center;">跳阶段</td><td style="text-align:center;">skipstg</td></tr><tr><td style="text-align:center;">强制预备</td><td style="text-align:center;">force-prep</td></tr></tbody></table><h2 id="_11-3-1-鱼眼" tabindex="-1">11.3.1 鱼眼 <a class="header-anchor" href="#_11-3-1-鱼眼" aria-label="Permalink to &quot;11.3.1 鱼眼&quot;">​</a></h2><p><code>鱼眼</code> / <code>fe</code> 表示应使用这样的手法：</p><ol><li>在可用的采集力不足以高质量地使用 4 次抛竿时，等待。</li><li>等待时，如刚才钓到的鱼类符合钓法中需要拍击水面的鱼，则使用拍击水面。</li><li>等待时，如刚才钓到的鱼类符合钓法中用来以小钓大的目标，则使用熟练妙招，并尽可能使用专一垂钓。</li><li>可用的采集力足够时，使用鱼眼。</li><li>在鱼眼效果内抛竿 / 以小钓大的最后一次等待 / 咬饵结束时，回到第 1 步。</li><li>当前如果处在正常的窗口期内，不使用上面的手法。</li></ol><h2 id="_11-3-2-攒鱼计" tabindex="-1">11.3.2 攒鱼计 <a class="header-anchor" href="#_11-3-2-攒鱼计" aria-label="Permalink to &quot;11.3.2 攒鱼计&quot;">​</a></h2><p><code>攒鱼计</code> / <code>aa</code> 表示应使用可积攒「捕鱼人之计」的手法，即使用增加大尺寸概率的技能，且不使用「沙利亚克的恩宠」。在「捕鱼人之计」到达 10 层时停止。</p><ul><li>通常在固定的表达式中使用：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">平钓</span><span class="dsl-op">【</span><span class="dsl-id">29717</span><span class="dsl-op">】</span><span class="dsl-op">》</span><span class="dsl-bite">全部</span><span class="dsl-op">=</span><span class="dsl-modifier">攒鱼计</span><span class="dsl-sep">；</span>  </span>
<span class="line"><span class="dsl-mode">nm</span> <span class="dsl-op">[</span><span class="dsl-id">29717</span><span class="dsl-op">]</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">all</span> <span class="dsl-op">=</span> <span class="dsl-modifier">aa</span><span class="dsl-sep">;</span>  </span></code></pre></div><h2 id="_11-3-3-不撒饵" tabindex="-1">11.3.3 不撒饵 <a class="header-anchor" href="#_11-3-3-不撒饵" aria-label="Permalink to &quot;11.3.3 不撒饵&quot;">​</a></h2><p><code>不撒饵</code> / <code>nochum</code> 表示不使用「撒饵」。</p><h2 id="_11-3-4-无强心剂" tabindex="-1">11.3.4 无强心剂 <a class="header-anchor" href="#_11-3-4-无强心剂" aria-label="Permalink to &quot;11.3.4 无强心剂&quot;">​</a></h2><p><code>无强心剂</code> / <code>nocord</code> 表示不使用任何「强心剂」。</p><h2 id="_11-3-5-无恩宠" tabindex="-1">11.3.5 无恩宠 <a class="header-anchor" href="#_11-3-5-无恩宠" aria-label="Permalink to &quot;11.3.5 无恩宠&quot;">​</a></h2><p><code>无恩宠</code> / <code>nofavor</code> 表示不使用「沙利亚克的恩宠」来回复采集力。</p><h2 id="_11-3-6-允许溢出" tabindex="-1">11.3.6 允许溢出 <a class="header-anchor" href="#_11-3-6-允许溢出" aria-label="Permalink to &quot;11.3.6 允许溢出&quot;">​</a></h2><p><code>允许溢出</code> / <code>overflow</code> 表示即使采集力恢复技能会导致溢出而浪费采集力上限，也允许使用它们。例如「强心剂」和「沙利亚克的恩宠」。</p><h2 id="_11-3-7-梭哈" tabindex="-1">11.3.7 梭哈 <a class="header-anchor" href="#_11-3-7-梭哈" aria-label="Permalink to &quot;11.3.7 梭哈&quot;">​</a></h2><p><code>梭哈</code> / <code>all-in</code> 表示完全不保留模式所需采集力。例如 <code>大鱼</code> / <code>bf</code> 时保留的用作「大鱼猎手」的采集力；或 <code>耐心</code> / <code>pt</code> 时保留的用作「耐心II」的采集力。</p><h2 id="_11-3-8-钓组" tabindex="-1">11.3.8 钓组 <a class="header-anchor" href="#_11-3-8-钓组" aria-label="Permalink to &quot;11.3.8 钓组&quot;">​</a></h2><p><code>钓组</code> / <code>snag</code> 表示维持技能「钓组」的状态效果。</p><h2 id="_11-3-9-收藏品" tabindex="-1">11.3.9 收藏品 <a class="header-anchor" href="#_11-3-9-收藏品" aria-label="Permalink to &quot;11.3.9 收藏品&quot;">​</a></h2><p><code>收藏品</code> / <code>coll</code> 表示维持技能「收藏品采集」的状态效果。</p><h2 id="_11-3-10-不收集" tabindex="-1">11.3.10 不收集 <a class="header-anchor" href="#_11-3-10-不收集" aria-label="Permalink to &quot;11.3.10 不收集&quot;">​</a></h2><p><code>不收集</code> / <code>nocoll</code> 表示在钓上可收为收藏品的鱼类时，不将其收为收藏品。</p><h2 id="_11-3-11-大尺寸" tabindex="-1">11.3.11 大尺寸 <a class="header-anchor" href="#_11-3-11-大尺寸" aria-label="Permalink to &quot;11.3.11 大尺寸&quot;">​</a></h2><p><code>大尺寸</code> / <code>large</code> 表示应采用尽可能提升鱼类的大尺寸概率的手法。例如使用「大鱼猎手」或「耐心II」。</p><h2 id="_11-3-12-大鱼知识" tabindex="-1">11.3.12 大鱼知识 <a class="header-anchor" href="#_11-3-12-大鱼知识" aria-label="Permalink to &quot;11.3.12 大鱼知识&quot;">​</a></h2><p><code>大鱼知识</code> / <code>bfg</code> 表示应尽可能在合适时使用「大鱼的知识」，同时保留「大鱼的知识」所需的「捕鱼人之计」。</p><ul><li>合适的时机如：在钓法中不存在拍击水面或专一垂钓目标时，否则要求持有拍击水面或专一垂钓效果。</li></ul><h2 id="_11-3-13-鱼篓" tabindex="-1">11.3.13 鱼篓 <a class="header-anchor" href="#_11-3-13-鱼篓" aria-label="Permalink to &quot;11.3.13 鱼篓&quot;">​</a></h2><p><code>鱼篓</code> / <code>sh</code> 表示应采用尽可能提升鱼类的大尺寸概率并获取更多游动饵的手法。是 <a href="#_8-游动饵">8.游动饵</a> 的显式表达，但不等效。</p><h2 id="_11-3-14-鱼篓专一" tabindex="-1">11.3.14 鱼篓专一 <a class="header-anchor" href="#_11-3-14-鱼篓专一" aria-label="Permalink to &quot;11.3.14 鱼篓专一&quot;">​</a></h2><p><code>鱼篓专一</code> / <code>sh-ic</code> 搭配 <code>@专一</code> / <code>@ic</code> 使用。表示在钓到用来以小钓大的目标鱼类时，应尽可能使用这样的连招，以获取更多的以小钓大机会：先使用「熟练妙招」将其保留为游动饵，然后使用「专一垂钓」。</p><ul><li>例如钓场之王「海牛灾星」，用来以小钓大的「火焰丽鱼」比较难钓到：</li></ul><div class="language-angex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">angex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code data-angex-highlighted="true"><span class="line"><span class="dsl-mode">耐心</span><span class="dsl-op">【</span><span class="dsl-name">黄金幼虫</span><span class="dsl-op">|</span><span class="dsl-id">43849</span><span class="dsl-op">】</span><span class="dsl-op">@</span><span class="dsl-time">0802</span><span class="dsl-op">-</span><span class="dsl-time">1200</span><span class="dsl-op">（</span><span class="dsl-name">阴云</span><span class="dsl-op">|</span><span class="dsl-id">3</span><span class="dsl-op">=》</span><span class="dsl-name">小雨</span><span class="dsl-op">|</span><span class="dsl-id">7</span><span class="dsl-op">）</span><span class="dsl-op">》</span><span class="dsl-op">~</span><span class="dsl-time">9</span><span class="dsl-op">+</span><span class="dsl-time">17</span><span class="dsl-bite">！！</span><span class="dsl-op">@</span><span class="dsl-trigger">专一</span><span class="dsl-op">【</span><span class="dsl-name">火焰丽鱼</span><span class="dsl-op">|</span><span class="dsl-id">43701</span><span class="dsl-op">】</span><span class="dsl-op">》</span><span class="dsl-bite">！！！</span><span class="dsl-op">=</span><span class="dsl-op">【</span><span class="dsl-name">海牛灾星</span><span class="dsl-op">|</span><span class="dsl-id">49795</span><span class="dsl-op">】</span><span class="dsl-sep">；</span><span class="dsl-modifier">不撒饵</span><span class="dsl-sep">、</span><span class="dsl-modifier">鱼篓专一</span><span class="dsl-sep">、</span><span class="dsl-modifier">引诱</span><span class="dsl-sep">；</span>  </span>
<span class="line"><span class="dsl-mode">pt</span> <span class="dsl-op">[</span><span class="dsl-name">Golden Stonefly Nymph</span><span class="dsl-op">|</span><span class="dsl-id">43849</span><span class="dsl-op">]</span> <span class="dsl-op">@</span><span class="dsl-time">0802</span> <span class="dsl-op">-</span> <span class="dsl-time">1200</span> <span class="dsl-op">(</span><span class="dsl-name">Clouds</span><span class="dsl-op">|</span><span class="dsl-id">3</span><span class="dsl-op"> =&gt; </span><span class="dsl-name">Rain</span><span class="dsl-op">|</span><span class="dsl-id">7</span><span class="dsl-op">)</span> <span class="dsl-op">&gt;</span> <span class="dsl-op">~</span> <span class="dsl-time">9</span> <span class="dsl-op">+</span> <span class="dsl-time">17</span> <span class="dsl-bite">!!</span> <span class="dsl-op">@</span><span class="dsl-trigger">ic</span> <span class="dsl-op">[</span><span class="dsl-name">Hunu Peacock Bass</span><span class="dsl-op">|</span><span class="dsl-id">43701</span><span class="dsl-op">]</span> <span class="dsl-op">&gt;</span> <span class="dsl-bite">!!!</span> <span class="dsl-op">=</span> <span class="dsl-op">[</span><span class="dsl-name">Punutiy Pain</span><span class="dsl-op">|</span><span class="dsl-id">49795</span><span class="dsl-op">]</span><span class="dsl-sep">;</span> <span class="dsl-modifier">nochum</span> <span class="dsl-op">|</span><span class="dsl-op">|</span> <span class="dsl-modifier">sh-ic</span> <span class="dsl-op">|</span><span class="dsl-op">|</span> <span class="dsl-modifier">lure</span><span class="dsl-sep">;</span>  </span></code></pre></div><h2 id="_11-3-15-等待专一" tabindex="-1">11.3.15 等待专一 <a class="header-anchor" href="#_11-3-15-等待专一" aria-label="Permalink to &quot;11.3.15 等待专一&quot;">​</a></h2><p><code>等待专一</code> / <code>waitic</code> 表示在钓到应「专一垂钓」的目标时，如果采集力不足，则等待采集力。</p><p>在同时存在 <code>确保多提</code> / <code>mhs</code> 时，也应等待复数效果提钩技能所需的采集力，即先使用「专一垂钓」，然后等待复数效果提钩技能所需的采集力。</p><h2 id="_11-3-16-等待华丽" tabindex="-1">11.3.16 等待华丽 <a class="header-anchor" href="#_11-3-16-等待华丽" aria-label="Permalink to &quot;11.3.16 等待华丽&quot;">​</a></h2><p><code>等待华丽</code> / <code>wait-sh</code> 表示在「华丽提钩」进入冷却后，应等待，直到冷却时间小于目标的最短咬饵时间，再继续钓鱼。</p><h2 id="_11-3-17-套娃" tabindex="-1">11.3.17 套娃 <a class="header-anchor" href="#_11-3-17-套娃" aria-label="Permalink to &quot;11.3.17 套娃&quot;">​</a></h2><p><code>套娃</code> / <code>mooch-loop</code> 表示应使用为以小钓大循环优化的手法。</p><p>如：在耐心系状态效果即将结束时，再次使用耐心II刷新其时间，以防止以小钓大循环中断；如果在钓到可以小钓大的鱼时，确保钓上鱼类可以小钓大的效果已经结束，则使用熟练妙招将其保留为游动饵，然后再次换上以继续以小钓大循环。</p><h2 id="_11-3-18-引诱" tabindex="-1">11.3.18 引诱 <a class="header-anchor" href="#_11-3-18-引诱" aria-label="Permalink to &quot;11.3.18 引诱&quot;">​</a></h2><p><code>引诱</code> / <code>lure</code> 表示应按当前钓法使用「雄心之饵」或「谦逊之饵」直到最大层数或触发确保效果。</p><h2 id="_11-3-19-雄心" tabindex="-1">11.3.19 雄心 <a class="header-anchor" href="#_11-3-19-雄心" aria-label="Permalink to &quot;11.3.19 雄心&quot;">​</a></h2><p><code>雄心</code> / <code>a-lure</code> 表示应使用「雄心之饵」。单独出现时，是 <code>引诱</code> / <code>lure</code> 的显式表达，表示应使用直到最大层数或触发确保效果。</p><h2 id="_11-3-20-谦逊" tabindex="-1">11.3.20 谦逊 <a class="header-anchor" href="#_11-3-20-谦逊" aria-label="Permalink to &quot;11.3.20 谦逊&quot;">​</a></h2><p><code>谦逊</code> / <code>m-lure</code> 表示应使用「谦逊之饵」。单独出现时，是 <code>引诱</code> / <code>lure</code> 的显式表达，表示应使用直到最大层数或触发确保效果。</p><h2 id="_11-3-21-鱼影" tabindex="-1">11.3.21 鱼影 <a class="header-anchor" href="#_11-3-21-鱼影" aria-label="Permalink to &quot;11.3.21 鱼影&quot;">​</a></h2><p><code>鱼影</code> / <code>shadow</code> 表示应按当前钓法使用「雄心之饵」或「谦逊之饵」直到触发「鱼影出现提示语」。如果直到满层也未触发，则使用歇竿；如果同时存在 <code>引诱</code> / <code>lure</code> 则不使用歇竿。</p><h2 id="_11-3-22-重随" tabindex="-1">11.3.22 重随 <a class="header-anchor" href="#_11-3-22-重随" aria-label="Permalink to &quot;11.3.22 重随&quot;">​</a></h2><p><code>重随</code> / <code>re-roll</code> 表示应在等待时间超过指定的最大咬饵时间时，使用「雄心之饵」或「谦逊之饵」来重新获取抛竿快照。在使用诱饵技能导致的咬饵真空期结束之后，如果仍未有咬饵，则再次使用。</p><h2 id="_11-3-23-回收" tabindex="-1">11.3.23 回收 <a class="header-anchor" href="#_11-3-23-回收" aria-label="Permalink to &quot;11.3.23 回收&quot;">​</a></h2><p><code>回收</code> / <code>recy</code> 配合阶段参数中的复数效果提钩技能，表示应在采集力足够使用「大鱼猎手」与钓法中的复数效果提钩技能时，使用「大鱼猎手」以利用稍后的复数效果提钩技能来获取多层捕鱼人之计。</p><h2 id="_11-3-24-加钩" tabindex="-1">11.3.24 加钩 <a class="header-anchor" href="#_11-3-24-加钩" aria-label="Permalink to &quot;11.3.24 加钩&quot;">​</a></h2><p><code>加钩</code> / <code>mh</code> 表示应尽可能在合适时使用「加钩」。</p><ul><li>合适的时机如：在钓法中不存在拍击水面或专一垂钓目标时，否则要求持有拍击水面或专一垂钓效果。</li></ul><h2 id="_11-3-25-确保多提" tabindex="-1">11.3.25 确保多提 <a class="header-anchor" href="#_11-3-25-确保多提" aria-label="Permalink to &quot;11.3.25 确保多提&quot;">​</a></h2><p><code>确保多提</code> / <code>mhs</code> 表示应保留更多的采集力以确保能使用钓法中采集力消耗最多的复数类型提钩技能。</p><h2 id="_11-3-26-多提回退" tabindex="-1">11.3.26 多提回退 <a class="header-anchor" href="#_11-3-26-多提回退" aria-label="Permalink to &quot;11.3.26 多提回退&quot;">​</a></h2><p><code>多提回退</code> / <code>mhs-back</code> 表示在无法使用「三重提钩」时，应尝试「双重提钩」。</p><h2 id="_11-3-27-银星" tabindex="-1">11.3.27 银星 <a class="header-anchor" href="#_11-3-27-银星" aria-label="Permalink to &quot;11.3.27 银星&quot;">​</a></h2><p><code>银星</code> / <code>silver</code> 表示应在满足银星需求时提前提交探索任务。</p><h2 id="_11-3-28-跳阶段" tabindex="-1">11.3.28 跳阶段 <a class="header-anchor" href="#_11-3-28-跳阶段" aria-label="Permalink to &quot;11.3.28 跳阶段&quot;">​</a></h2><p><code>跳阶段</code> / <code>skipstg</code> 表示计数器应以在当前钓场钓到的鱼类数量作为计数来源，而非本段钓法开始后钓到的鱼类数量。同时，使用复数效果提钩技能时也不再因为可能溢出而选择数量更少的复数效果提钩技能。（原来的钓法：假如「三重提钩」会导致计数器溢出，则使用数量更少的提钩技能）</p><h2 id="_11-3-29-强制预备" tabindex="-1">11.3.29 强制预备 <a class="header-anchor" href="#_11-3-29-强制预备" aria-label="Permalink to &quot;11.3.29 强制预备&quot;">​</a></h2><p><code>强制预备</code> / <code>force-prep</code> 表示无论距离窗口期多久，都立刻开始窗口期前的准备工作。例如：捕鱼人之计、可以小钓大的鱼、游动饵、捕鱼人之识的触发等。</p><h2 id="_12-阶段钓法" tabindex="-1">12. 阶段钓法 <a class="header-anchor" href="#_12-阶段钓法" aria-label="Permalink to &quot;12. 阶段钓法&quot;">​</a></h2><p>施工中……</p><h2 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to &quot;附录&quot;">​</a></h2><h2 id="预设表格" tabindex="-1">预设表格 <a class="header-anchor" href="#预设表格" aria-label="Permalink to &quot;预设表格&quot;">​</a></h2><p>在<a href="https://docs.qq.com/sheet/DVlNaQ012amF4SW1G?tab=yirja0" target="_blank" rel="noreferrer">预设表格</a>，你可以找到实际场景下的实用钓法表达式作为例子来参考。</p><h2 id="测试条件" tabindex="-1">测试条件 <a class="header-anchor" href="#测试条件" aria-label="Permalink to &quot;测试条件&quot;">​</a></h2><p>游戏进度：已可游玩 7.00 补丁的内容，以便测试<br> 捕鱼人：需要已经满级，且已经学习技能 耐心II</p><h2 id="测试地点" tabindex="-1">测试地点 <a class="header-anchor" href="#测试地点" aria-label="Permalink to &quot;测试地点&quot;">​</a></h2><p><strong>- 永夏岛北：</strong><br> 位置：拉诺西亚-东拉诺西亚，地图东北方的岛屿周围。<br> 在使用「沙蚕」作为钓饵时，永夏岛北有最稳定的咬饵。在抛竿后，咬饵的必定是「梅尔托尔虾虎」，在使用「梅尔托尔虾虎」来以小钓大后，咬饵的必定是「梭子鰆」。</p><p><strong>- 深壕：</strong><br> 位置：北洋地域-迷津，地图中央的围绕圆形地图块的沟渠。<br> 在用「以太螯虾」来以小钓大后，咬饵的仍可能是「以太螯虾」。可以测试「以小钓大循环」和捕鱼人之识。</p><p><strong>- 圣法斯里克天庭：</strong><br> 位置：诺弗兰特-伊尔美格，地图东南方的区域的河流。<br> 测试条件：有一把「诺弗兰特远见钓竿」（莫雯工具，物品 ID 41190），你需要装上前述的钓竿才能钓上测试所需的鱼类。<br> 在这里非常容易测试捕鱼人之识和捕鱼人之识结束时的确保咬饵效果。只需要钓上3条「丰饶虹鳉」就能触发对应「圣法斯里克的石头脑袋」的捕鱼人之识。</p>`,342)])])}const b=a(e,[["render",d]]);export{g as __pageData,b as default};
